parameters.jsCode:
for (const item of items) {
  const text = item.json.output || "";

  const statusMatch = text.match(/"status":\s*"([^"]+)"/);
  const nameMatch = text.match(/"name":\s*"([^"]+)"/);
  const emailMatch = text.match(/"email":\s*"([^"]+)"/);
  const interestMatch = text.match(/"interest":\s*"([^"]+)"/);

  item.json.status = statusMatch ? statusMatch[1] : "in_progress";
  item.json.name = nameMatch ? nameMatch[1] : "";
  item.json.email = emailMatch ? emailMatch[1] : "";
  item.json.interest = interestMatch ? interestMatch[1] : "";
}

return items;

